+const reloadStateFilename = "reload-status.json"
+
+// reloadTransaction serializes transactional reloads and retains the last fully
+// applied configuration so a partial application can be reversed.
+type reloadTransaction struct {
+	enabled bool
+	path    string
+	logger  *slog.Logger
+
+	mu       sync.RWMutex
+	lastGood *config.Config
+	status   api_v1.ReloadStatus
+}
+
+func newTransactionalReload(enabled bool, storagePath string, logger *slog.Logger) *reloadTransaction {
+	r := &reloadTransaction{
+		enabled: enabled,
+		path:    filepath.Join(storagePath, reloadStateFilename),
+		logger:  logger,
+		status: api_v1.ReloadStatus{
+			ErrorCategory:     "none",
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]float64{},
+		},
+	}
+	if enabled {
+		r.loadStatus()
+	}
+	return r
+}
+
+func (r *reloadTransaction) Status() api_v1.ReloadStatus {
+	r.mu.RLock()
+	defer r.mu.RUnlock()
+	return cloneReloadStatus(r.status)
+}
+
+func cloneReloadStatus(s api_v1.ReloadStatus) api_v1.ReloadStatus {
+	s.AppliedReloaders = append([]string{}, s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]float64, len(s.ReloaderTimingsMS))
+	for name, duration := range s.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[name] = duration
+	}
+	return s
+}
+
+func (r *reloadTransaction) loadStatus() {
+	b, err := os.ReadFile(r.path)
+	if err != nil {
+		return
+	}
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil || !validReloadStatus(status) {
+		if err != nil {
+			r.logger.Warn("Ignoring invalid persisted reload status", "file", r.path, "err", err)
+		}
+		return
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]float64{}
+	}
+	r.status = status
+}
+
+func validReloadStatus(status api_v1.ReloadStatus) bool {
+	switch status.ErrorCategory {
+	case "none", "load_error", "apply_error", "rollback_error":
+		return true
+	default:
+		return false
+	}
+}
+
+func (r *reloadTransaction) persistStatus() {
+	b, err := json.Marshal(r.status)
+	if err != nil {
+		r.logger.Error("Unable to marshal reload status", "err", err)
+		return
+	}
+	tmp := r.path + ".tmp"
+	if err := os.WriteFile(tmp, b, 0o600); err != nil {
+		r.logger.Error("Unable to persist reload status", "file", r.path, "err", err)
+		return
+	}
+	if err := os.Rename(tmp, r.path); err != nil {
+		r.logger.Error("Unable to persist reload status", "file", r.path, "err", err)
+	}
+}
+
+// InitialLoad installs the startup configuration. It intentionally does not
+// create a reload outcome because no reload attempt has occurred yet.
+func (r *reloadTransaction) InitialLoad(filename string, enableExemplarStorage bool, logger *slog.Logger, interval *safePromQLNoStepSubqueryInterval, rls ...reloader) error {
+	if !r.enabled {
+		return reloadConfig(filename, enableExemplarStorage, logger, interval, func(bool) {}, rls...)
+	}
+
+	r.mu.Lock()
+	defer r.mu.Unlock()
+	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		return err
+	}
+	if err := applyReloaders(conf, rls, nil, nil); err != nil {
+		return err
+	}
+	updateGoGC(conf, logger)
+	interval.Set(conf.GlobalConfig.EvaluationInterval)
+	r.lastGood = conf
+	return nil
+}
+
+func (r *reloadTransaction) Reload(filename string, enableExemplarStorage bool, logger *slog.Logger, interval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	if !r.enabled {
+		return reloadConfig(filename, enableExemplarStorage, logger, interval, callback, rls...)
+	}
+
+	r.mu.Lock()
+	defer r.mu.Unlock()
+	outcome := api_v1.ReloadStatus{
+		LastReloadID:      time.Now().UTC().Format(time.RFC3339Nano),
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	}
+	conf, err := loadReloadConfig(filename, enableExemplarStorage, logger)
+	if err != nil {
+		outcome.ErrorCategory = "load_error"
+		outcome.ErrorMessage = err.Error()
+		r.record(outcome)
+		callback(false)
+		return err
+	}
+
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		outcome.ReloaderTimingsMS[rl.name] = float64(time.Since(start)) / float64(time.Millisecond)
+		if err == nil {
+			outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
+			continue
+		}
+
+		outcome.ErrorCategory = "apply_error"
+		outcome.ErrorMessage = err.Error()
+		outcome.FailedReloader = rl.name
+		if len(outcome.AppliedReloaders) > 0 && r.lastGood != nil {
+			outcome.RollbackAttempted = true
+			for i := len(outcome.AppliedReloaders) - 1; i >= 0; i-- {
+				name := outcome.AppliedReloaders[i]
+				start := time.Now()
+				rollbackErr := rls[i].reloader(r.lastGood)
+				outcome.ReloaderTimingsMS["rollback_"+name] = float64(time.Since(start)) / float64(time.Millisecond)
+				if rollbackErr != nil {
+					outcome.ErrorCategory = "rollback_error"
+					outcome.ErrorMessage = fmt.Sprintf("%s; rollback of %s failed: %v", err, name, rollbackErr)
+					break
+				}
+			}
+			outcome.RollbackSuccessful = outcome.ErrorCategory != "rollback_error"
+		}
+		r.record(outcome)
+		callback(false)
+		return fmt.Errorf("failed to apply configuration with %s: %w", rl.name, err)
+	}
+
+	updateGoGC(conf, logger)
+	interval.Set(conf.GlobalConfig.EvaluationInterval)
+	r.lastGood = conf
+	outcome.LastReloadSuccessful = true
+	outcome.ErrorCategory = "none"
+	r.record(outcome)
+	callback(true)
+	return nil
+}
+
+func (r *reloadTransaction) record(outcome api_v1.ReloadStatus) {
+	r.status = outcome
+	r.persistStatus()
+}
+
+func loadReloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger) (*config.Config, error) {
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		return nil, fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+	return conf, nil
+}
+
+func applyReloaders(conf *config.Config, rls []reloader, applied *[]string, timings map[string]float64) error {
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		if timings != nil {
+			timings[rl.name] = float64(time.Since(start)) / float64(time.Millisecond)
+		}
+		if err != nil {
+			return fmt.Errorf("failed to apply configuration with %s: %w", rl.name, err)
+		}
+		if applied != nil {
+			*applied = append(*applied, rl.name)
+		}
+	}
+	return nil
+}
