+func (r *reloadTransaction) Reload(filename string, enableExemplarStorage bool, logger *slog.Logger, interval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	if !r.enabled {
+		return reloadConfig(filename, enableExemplarStorage, logger, interval, callback, rls...)
