+				}
+			}
+			outcome.RollbackSuccessful = outcome.ErrorCategory != "rollback_error"
+		}
+		r.record(outcome)
+		callback(false)
+		return fmt.Errorf("failed to apply configuration with %s: %w", rl.name, err)
